import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

type CardDebt = { name: string; balance: number; apr: number; min: number };

const FAQS = [
  { q: "What is the avalanche method for paying off debt?", a: "The avalanche method pays required minimums on every debt, then sends extra money to the highest APR balance first. It usually saves the most interest." },
  { q: "What is the snowball method?", a: "The snowball method pays minimums on every debt, then sends extra money to the smallest balance first. It can create faster early wins." },
  { q: "Which method saves more money - avalanche or snowball?", a: "The avalanche method usually saves more money because it attacks the highest interest rate first, but the snowball method can feel easier to stick with." },
  { q: "Should you consolidate credit card debt?", a: "Consolidation may help if it lowers your interest rate, simplifies payments, and does not encourage new card balances." },
  { q: "How do balance transfers help pay off credit cards?", a: "A balance transfer can move debt to a lower promotional APR, giving more of each payment a chance to reduce principal." },
];

const money = (value: number, digits = 0) => formatCurrencyValue(Number.isFinite(value) ? value : 0, { maximumFractionDigits: digits });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function methodResult(cards: CardDebt[], extra: number, method: "avalanche" | "snowball") {
  let balances = cards.map((card) => ({ ...card }));
  let totalInterest = 0;
  let totalPaid = 0;
  const order: string[] = [];
  let months = 0;
  while (months < 1200 && balances.some((d) => d.balance > 0.01)) {
    months++;
    for (const d of balances) {
      if (d.balance <= 0.01) continue;
      const interest = d.balance * (d.apr / 100 / 12);
      d.balance += interest;
      totalInterest += interest;
    }
    for (const d of balances) {
      if (d.balance <= 0.01) continue;
      const pay = Math.min(d.min, d.balance);
      d.balance -= pay;
      totalPaid += pay;
    }
    let extraLeft = extra;
    while (extraLeft > 0.01 && balances.some((d) => d.balance > 0.01)) {
      const target = balances.filter((d) => d.balance > 0.01).sort((a, b) => method === "avalanche" ? b.apr - a.apr : a.balance - b.balance)[0];
      if (!order.includes(target.name)) order.push(target.name);
      const pay = Math.min(extraLeft, target.balance);
      target.balance -= pay;
      totalPaid += pay;
      extraLeft -= pay;
    }
  }
  return { months: months >= 1200 ? Infinity : months, totalInterest, totalPaid, order };
}

export default function CreditCardsPayoffCalculator() {
  useCurrencyVersion();
  const [cards, setCards] = useState<CardDebt[]>([
    { name: "Card 1", balance: 2500, apr: 22, min: 75 },
    { name: "Card 2", balance: 5000, apr: 18, min: 125 },
    { name: "Card 3", balance: 1200, apr: 25, min: 40 },
  ]);
  const [extra, setExtra] = useState(300);
  const avalanche = useMemo(() => methodResult(cards, extra, "avalanche"), [cards, extra]);
  const snowball = useMemo(() => methodResult(cards, extra, "snowball"), [cards, extra]);
  const updateCard = (index: number, key: keyof CardDebt, value: string | number) => setCards((list) => list.map((card, i) => i === index ? { ...card, [key]: value } : card));
  const addCard = () => setCards((list) => list.length >= 10 ? list : [...list, { name: `Card ${list.length + 1}`, balance: 1000, apr: 19, min: 35 }]);
  const example = [
    { card: "Card A", balance: 2500, apr: 22, min: 75 },
    { card: "Card B", balance: 5000, apr: 18, min: 125 },
    { card: "Card C", balance: 1200, apr: 25, min: 40 },
  ];

  return (
    <>
      <SEOHead title="Free Credit Cards Payoff Calculator Online - Compare Avalanche vs Snowball Method Instantly | CalcHive" description="Free online credit cards payoff calculator. Enter multiple credit cards and compare avalanche vs snowball payoff methods to find which saves the most money instantly. 100% free, no signup required." canonical="/credit-cards-payoff-calculator" keywords="free credit cards payoff calculator, multiple credit card payoff calculator free, avalanche vs snowball calculator free online, credit card debt elimination calculator free, pay off credit cards calculator free" category="Financial Calculators" breadcrumbName="Free Credit Cards Payoff Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Credit Cards Payoff Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Compare avalanche and snowball payoff strategies for up to 10 credit cards.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-3 mb-6">{cards.map((card, index) => <div key={index} className="grid grid-cols-2 sm:grid-cols-4 gap-3 bg-accent/40 border border-border rounded-xl p-3"><input value={card.name} onChange={(e) => updateCard(index, "name", e.target.value)} className={inputClass} aria-label="Card name" /><input type="number" value={card.balance} onChange={(e) => updateCard(index, "balance", Number(e.target.value))} className={inputClass} aria-label="Balance" /><input type="number" value={card.apr} onChange={(e) => updateCard(index, "apr", Number(e.target.value))} className={inputClass} aria-label="APR" /><input type="number" value={card.min} onChange={(e) => updateCard(index, "min", Number(e.target.value))} className={inputClass} aria-label="Minimum payment" /></div>)}</div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-8"><button type="button" onClick={addCard} className="px-4 py-3 rounded-xl bg-primary text-primary-foreground font-bold">Add Card</button><div><label className="text-sm font-semibold text-foreground block mb-2">Extra monthly payoff budget</label><input type="number" value={extra} onChange={(e) => setExtra(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4"><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Avalanche</p><p className="text-4xl font-black text-white">{Number.isFinite(avalanche.months) ? `${avalanche.months} mo` : "N/A"}</p><p className="text-white/80 text-sm mt-2">Interest: {money(avalanche.totalInterest)}</p></div><div className="bg-accent/60 border border-border rounded-2xl p-6 text-center"><p className="text-xs font-semibold uppercase tracking-widest text-muted-foreground mb-1">Snowball</p><p className="text-4xl font-black text-foreground">{Number.isFinite(snowball.months) ? `${snowball.months} mo` : "N/A"}</p><p className="text-muted-foreground text-sm mt-2">Interest: {money(snowball.totalInterest)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Pay Off Multiple Credit Cards for Free</h2><p className="text-muted-foreground leading-relaxed">Enter each balance, APR, and minimum payment to compare payoff strategies with the same extra monthly budget.</p>
          <h2 className="text-2xl font-bold text-foreground">Avalanche vs Snowball - Which Debt Payoff Method Is Better</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Avalanche vs Snowball Method Comparison - Example with 3 Cards</caption><thead className="bg-muted/60"><tr>{["Card", "Balance", "APR", "Minimum Payment", "Avalanche Payoff Order", "Snowball Payoff Order"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{example.map((row) => <tr key={row.card}><td className="py-2.5 px-3 font-semibold">{row.card}</td><td className="py-2.5 px-3">{money(row.balance)}</td><td className="py-2.5 px-3">{row.apr}%</td><td className="py-2.5 px-3">{money(row.min)}</td><td className="py-2.5 px-3">{[...example].sort((a, b) => b.apr - a.apr).findIndex((x) => x.card === row.card) + 1}</td><td className="py-2.5 px-3">{[...example].sort((a, b) => a.balance - b.balance).findIndex((x) => x.card === row.card) + 1}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Multi-Card Debt Elimination Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">The avalanche method saves {money(Math.max(0, snowball.totalInterest - avalanche.totalInterest))} more interest in this scenario. Payoff order: avalanche {avalanche.order.join(", ") || "N/A"}; snowball {snowball.order.join(", ") || "N/A"}.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/credit-cards-payoff-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


